import ProductWorkspace from '../components/ProductWorkspace';
import '../styles.css';

export default function Home() {
  return (
    <div className="min-h-screen bg-gray-50 flex flex-col items-center py-8">
      <header className="text-center mb-8 px-4">
        <h1 className="text-4xl font-bold text-gray-900">Otayori Route</h1>
        <p className="text-xl text-gray-600 mt-2">Turn notices into family action cards with evidence & uncertainty.</p>
        <p className="mt-4 text-sm text-red-700 bg-red-100 p-3 rounded-md border border-red-200">
          Disclaimer: This is an AI-generated demo. Always verify information from original sources before acting.
        </p>
      </header>
      <main className="w-full max-w-7xl flex-grow px-4">
        <ProductWorkspace />
      </main>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { sampleNotice, sampleActionCards, sampleSourceReferences, ActionCard, SourceReference } from '../data/product';

interface Highlight {
  startIndex: number;
  endIndex: number;
}

const ProductWorkspace: React.FC = () => {
  const [rawNoticeText, setRawNoticeText] = useState<string>(sampleNotice.rawText);
  const [actionCards, setActionCards] = useState<ActionCard[]>(sampleActionCards);
  const [sourceReferences, setSourceReferences] = useState<SourceReference[]>(sampleSourceReferences);
  const [highlightedSourceRef, setHighlightedSourceRef] = useState<Highlight | null>(null);

  // Function to render the notice text with highlights
  const renderNoticeWithHighlights = (text: string, highlight: Highlight | null) => {
    if (!highlight) {
      return <p>{text}</p>;
    }

    const parts = [];
    let lastIndex = 0;

    if (highlight.startIndex > 0) {
      parts.push(text.substring(lastIndex, highlight.startIndex));
    }
    parts.push(
      <mark key="highlight" className="highlight-text bg-yellow-200 p-0.5 rounded">
        {text.substring(highlight.startIndex, highlight.endIndex)}
      </mark>
    );
    lastIndex = highlight.endIndex;

    if (lastIndex < text.length) {
      parts.push(text.substring(lastIndex));
    }

    return (
      <p>
        {parts.map((part, index) => typeof part === 'string' ? <span key={index}>{part}</span> : part)}
      </p>
    );
  };

  const handleSourceReferenceClick = (sourceRefId: string) => {
    const ref = sourceReferences.find(sr => sr.id === sourceRefId);
    if (ref) {
      setHighlightedSourceRef({ startIndex: ref.startIndex, endIndex: ref.endIndex });
      // Scroll to the highlighted text
      const noticeDisplay = document.getElementById('original-notice-display');
      if (noticeDisplay) {
        // A simpler way to scroll without calculating exact pixel offset:
        // Create a temporary span around the highlighted text and scroll to it.
        // For this demo, just setting the highlight is sufficient.
        // If a real scroll is needed, one would usually use a ref and scrollIntoView
        // or calculate position.
        // For MVP, visual highlight is the primary interaction.
      }
    }
  };

  return (
    <div className="product-workspace grid grid-cols-1 lg:grid-cols-2 gap-8">
      {/* Left Panel: Notice Input and Original Notice Display */}
      <div className="notice-panel bg-white p-6 rounded-lg shadow-md flex flex-col">
        <h2 className="text-2xl font-semibold mb-4 text-gray-800">Original Notice</h2>
        <div className="mb-6">
          <label htmlFor="notice-input" className="block text-gray-700 text-sm font-bold mb-2">
            Paste your school or civic notice here (demo uses sample data):
          </label>
          <textarea
            id="notice-input"
            className="w-full p-3 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500 bg-gray-50"
            rows={6}
            value={rawNoticeText}
            readOnly // For MVP, we stick to static demo data
            placeholder="Paste your notice text here..."
          />
          <p className="text-sm text-gray-500 mt-2">Note: For this demo, input is read-only and displays a fixed sample notice to illustrate functionality.</p>
        </div>

        <div id="original-notice-display" className="flex-grow border border-gray-200 rounded-md p-4 bg-gray-50 overflow-y-auto text-sm leading-relaxed whitespace-pre-wrap">
          {renderNoticeWithHighlights(rawNoticeText, highlightedSourceRef)}
        </div>
      </div>

      {/* Right Panel: Action Cards Display */}
      <div className="action-cards-panel bg-white p-6 rounded-lg shadow-md flex flex-col">
        <h2 className="text-2xl font-semibold mb-4 text-gray-800">Extracted Action Cards</h2>
        <div className="space-y-4 flex-grow overflow-y-auto">
          {actionCards.length === 0 && (
            <p className="text-gray-500 italic">No action cards generated for this notice. Try pasting a detailed notice.</p>
          )}
          {actionCards.map((card) => (
            <div key={card.id} className="action-card border border-blue-200 bg-blue-50 rounded-lg p-4 shadow-sm relative">
              <h3 className="font-bold text-lg text-blue-800 mb-2">Action: {card.actionDescription}</h3>
              <p><span className="font-semibold">Who:</span> {card.actor}</p>
              {card.dueDate && <p><span className="font-semibold">When:</span> {new Date(card.dueDate).toLocaleDateString()}</p>}
              {card.materials && card.materials.length > 0 && <p><span className="font-semibold">Materials:</span> {card.materials.join(', ')}</p>}

              {card.uncertaintyFlag && (
                <div className="mt-2 p-2 bg-yellow-100 border border-yellow-300 rounded-md flex items-center">
                  <svg className="w-5 h-5 text-yellow-600 mr-2" fill="currentColor" viewBox="0 0 20 20" xmlns="http://www.w3.org/2000/svg"><path fillRule="evenodd" d="M8.257 3.099c.765-1.36 2.722-1.36 3.486 0l5.58 9.92c.75 1.334-.213 2.98-1.742 2.98H4.42c-1.53 0-2.493-1.646-1.743-2.98l5.58-9.92zM10 11a1 1 0 100-2 1 1 0 000 2zm1-1a1 1 0 11-2 0 1 1 0 012 0z" clipRule="evenodd"></path></svg>
                  <p className="text-yellow-800 font-medium">
                    Uncertainty: {card.confirmationQuestion || 'Information requires confirmation.'}
                  </p>
                </div>
              )}

              {card.sourceReferenceIds && card.sourceReferenceIds.length > 0 && (
                <div className="mt-3 text-sm text-gray-600">
                  <span className="font-semibold">Source: </span>
                  {card.sourceReferenceIds.map((refId, index) => (
                    <a
                      key={refId}
                      href="#original-notice-display"
                      onClick={(e) => { e.preventDefault(); handleSourceReferenceClick(refId); }}
                      className="text-blue-600 hover:underline mx-1"
                    >
                      [Ref {index + 1}]
                    </a>
                  ))}
                </div>
              )}
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default ProductWorkspace;

export interface Notice {
  id: string;
  rawText: string;
  ingestionTimestamp: string;
}

export interface ActionCard {
  id: string;
  noticeId: string;
  actor: string;
  actionDescription: string;
  dueDate?: string; // ISO date string
  materials?: string[];
  sourceReferenceIds: string[];
  uncertaintyFlag: boolean;
  confirmationQuestion?: string;
}

export interface SourceReference {
  id: string;
  noticeId: string;
  startIndex: number;
  endIndex: number;
  textSnippet: string;
}

