@tailwind base;
@tailwind components;
@tailwind utilities;

body {
  font-family: 'Inter', sans-serif;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

.product-workspace {
  min-height: calc(100vh - 180px); /* Adjust based on header/footer height */
  display: grid;
  grid-template-columns: 1fr;
}

@media (min-width: 1024px) {
  .product-workspace {
    grid-template-columns: 1fr 1fr;
  }
}

.notice-panel,
.action-cards-panel {
  height: calc(100vh - 220px); /* Further adjustment for inner panels */
  display: flex;
  flex-direction: column;
}

.highlight-text {
  background-color: #fcd34d; /* yellow-300 */
  padding: 0.1em 0.2em; /* Minimal padding for inline highlight */
  border-radius: 0.2em;
}

/* Ensure the scrollable areas take remaining space */
.notice-panel > div:last-child,
.action-cards-panel > div:last-child {
  flex-grow: 1;
  overflow-y: auto;
}
